'use strict';

/**
 * Sliding window rate limiting middleware for Express.js.
 *
 * This is a TRUE sliding window: it stores the timestamp of every request
 * per client and, on each incoming request, discards timestamps older than
 * `windowMs` before counting. There is no fixed-interval "reset" — the window
 * continuously slides with the current time.
 *
 * NOTE ON `req.ip` BEHIND PROXIES:
 *   `req.ip` reflects the socket's remote address unless Express's
 *   "trust proxy" setting is enabled. Behind a reverse proxy / load balancer
 *   (Nginx, Cloudflare, ELB, etc.) the socket address is the proxy's, so every
 *   client would share one bucket. Enable trust proxy so Express derives the
 *   real client IP from the `X-Forwarded-For` header:
 *
 *       app.set('trust proxy', 1); // or a specific subnet / true
 *
 *   Only trust proxy headers when you control the proxy in front of the app;
 *   otherwise clients can spoof `X-Forwarded-For` to evade or poison limits.
 */

/**
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000]   Window size in milliseconds.
 * @param {number} [options.maxRequests=100]  Max requests allowed per window.
 * @param {number} [options.cleanupMs=60000]  How often the cleanup timer runs.
 * @param {(req) => string} [options.keyGenerator]  Override how the client key
 *        is derived (defaults to `req.ip`).
 * @returns {Function & { close: () => void }} Express middleware with a
 *        `close()` method that clears the cleanup interval.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]>  — sorted ascending list of request timestamps (ms).
  const hits = new Map();

  /**
   * Drop all timestamps older than the window's lower bound.
   * Timestamps are appended in time order, so the first index that is
   * still within the window marks where the live entries begin.
   * @returns {number[]} a fresh array containing only in-window timestamps.
   */
  function prune(timestamps, windowStart) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= windowStart) {
      i++;
    }
    // Slice off the expired prefix (cheaper than repeated shift()).
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    const recent = prune(hits.get(key) || [], windowStart);

    if (recent.length >= maxRequests) {
      // Over the limit. The oldest in-window request is what must expire
      // before a slot frees up, so Retry-After is until that one leaves.
      hits.set(key, recent); // persist the pruned list
      const oldest = recent[0];
      const retryAfterMs = oldest + windowMs - now;
      const retryAfterSec = Math.max(1, Math.ceil(retryAfterMs / 1000));
      const resetEpoch = Math.ceil((oldest + windowMs) / 1000);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', resetEpoch);
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // do NOT call next()
    }

    // Under the limit: record this request and allow it through.
    recent.push(now);
    hits.set(key, recent);

    const remaining = maxRequests - recent.length;
    // When the window will be fully clear of the current oldest request.
    const resetEpoch = Math.ceil((recent[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', resetEpoch);

    next();
  };

  // Periodic cleanup: evict keys whose every timestamp has expired so the
  // Map doesn't grow unbounded with one-off clients.
  const cleanup = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const last = timestamps[timestamps.length - 1];
      if (last === undefined || last <= windowStart) {
        hits.delete(key);
      }
    }
  }, cleanupMs);

  // Don't let the cleanup timer keep the event loop (and process) alive.
  if (typeof cleanup.unref === 'function') {
    cleanup.unref();
  }

  // Allow callers to stop the timer explicitly (tests, graceful shutdown).
  middleware.close = function close() {
    clearInterval(cleanup);
    hits.clear();
  };

  return middleware;
}

