const express = require('express');
const createRateLimiter = require('./rateLimiter');

const app = express();

// IMPORTANT behind Nginx / Cloudflare / a load balancer: enable trust proxy
// so req.ip is the real client IP (from X-Forwarded-For) instead of the proxy's.
app.set('trust proxy', 1);

// 30 requests per 10 seconds, sliding.
const limiter = createRateLimiter({ windowMs: 10000, maxRequests: 30 });

app.use(limiter);

app.get('/', (req, res) => res.send('ok'));

const server = app.listen(3000, () => console.log('listening on :3000'));

// Graceful shutdown: stop the cleanup timer and free the server.
process.on('SIGTERM', () => {
  limiter.close();
  server.close();
});
