/**
 * rateLimiter.js
 * ==============
 * True sliding-window rate-limiting middleware for Express.js.
 *
 * Unlike fixed-window schemes (which reset a counter at a clock boundary and
 * can allow up to 2× maxRequests in a burst that straddles two windows), this
 * implementation stores a per-IP list of individual request timestamps.  On
 * every request it evicts timestamps that have fallen outside the window, then
 * checks the live count against the ceiling.  The window therefore slides
 * continuously — there is no reset boundary to exploit.
 */

'use strict';

/**
 * @typedef {object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window duration in ms.
 * @property {number} [maxRequests=100]  - Max requests allowed per window per IP.
 */

/**
 * @typedef {object} RateLimiter
 * @property {import('express').RequestHandler} middleware
 * @property {() => void}                        close
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param   {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;    // default: 100 req / window

  if (!Number.isFinite(windowMs)    || windowMs    <= 0)
    throw new RangeError('windowMs must be a positive number');
  if (!Number.isFinite(maxRequests) || maxRequests <= 0)
    throw new RangeError('maxRequests must be a positive number');

  /**
   * Central store: IP → sorted array of request timestamps (ms, ascending).
   *
   * Timestamps are always appended via Array#push so they remain in ascending
   * order without any explicit sort — wall-clock time is monotonically
   * increasing within a single process.  Eviction removes entries from the
   * front (oldest first), making the array behave as a sliding deque.
   *
   * Memory bound: at steady state each IP holds at most `maxRequests` entries.
   *
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ── Background cleanup ─────────────────────────────────────────────────────
  // Left unchecked, `store` accumulates an entry for every IP that has ever
  // sent a request.  Every 60 s we sweep for IPs whose *most recent* timestamp
  // is older than `windowMs` — meaning every timestamp for that IP would be
  // evicted on the next request anyway — and delete the whole entry.
  //
  // Checking only the last element is O(1) and sufficient because timestamps
  // are in ascending order; if the newest is stale, all are.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      if (timestamps.length === 0 ||
          timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // unref() tells the Node event loop not to keep the process alive solely
  // because this timer is still pending — critical for clean Jest teardowns
  // and graceful-shutdown scenarios.  Guard the call so the module stays
  // compatible with environments that wrap setInterval without returning a
  // real Timeout (e.g. some browser-targeted bundlers).
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  // ── Middleware ─────────────────────────────────────────────────────────────

  /**
   * Express request handler implementing the sliding-window algorithm.
   *
   * ── Proxy / trust-proxy note ──────────────────────────────────────────────
   * Express sets req.ip from X-Forwarded-For ONLY when the app is configured
   * to trust its upstream proxy:
   *
   *   app.set('trust proxy', 1);  // trust one hop (Nginx, AWS ALB, etc.)
   *
   * Without that setting, req.ip is always the raw TCP remote address.
   * Behind a load-balancer that means every user shares one bucket, defeating
   * per-client rate-limiting.  Conversely, enabling trust proxy when you are
   * NOT behind a trusted proxy lets clients forge X-Forwarded-For and bypass
   * the limiter entirely.  Only enable it when you control the proxy tier.
   * ──────────────────────────────────────────────────────────────────────────
   *
   * @type {import('express').RequestHandler}
   */
  function middleware(req, res, next) {
    const now    = Date.now();
    const cutoff = now - windowMs;

    // Resolve client identifier; fall back gracefully if req.ip is absent.
    const ip = req.ip ?? req.socket?.remoteAddress ?? 'unknown';

    // ── 1. Retrieve (or initialise) the timestamp list for this IP ───────────
    let timestamps = store.get(ip);
    if (timestamps === undefined) {
      timestamps = [];
      store.set(ip, timestamps);
    }

    // ── 2. Slide the window — evict timestamps older than the cutoff ─────────
    // The array is sorted ascending so stale entries form a contiguous prefix
    // at the front.  We find the first in-window index then splice once.
    // splice(0, k) is O(n) but n ≤ maxRequests so it is O(maxRequests) worst-
    // case and amortised O(1) when eviction and arrival rates are matched.
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= cutoff) {
      firstValid++;
    }
    if (firstValid > 0) {
      timestamps.splice(0, firstValid);
    }

    const currentCount = timestamps.length;

    // ── 3. Enforce the limit ─────────────────────────────────────────────────
    if (currentCount >= maxRequests) {
      // The oldest remaining timestamp tells us exactly when the next slot
      // opens:  oldestTimestamp + windowMs = the moment that request ages out.
      //
      //   retryAfter = (oldestInWindow + windowMs) - now
      //              = oldestInWindow - (now - windowMs)
      //              = oldestInWindow - cutoff          ← one fewer operation
      const oldestInWindow = timestamps[0]; // exists: currentCount >= maxRequests > 0
      const retryAfterMs   = (oldestInWindow + windowMs) - now;
      const retryAfterSec  = Math.ceil(retryAfterMs / 1000);

      res.setHeader('Retry-After', retryAfterSec);

      // ← Do NOT call next(). The request is rejected.
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // ── 4. Record this request and pass it through ───────────────────────────
    timestamps.push(now);

    // X-RateLimit-Reset = epoch-second at which the *oldest* request in the
    // current window expires and a new slot opens.  Clients can schedule a
    // precise retry instead of polling.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1_000);

    res.setHeader('X-RateLimit-Limit',     maxRequests);
    res.setHeader('X-RateLimit-Remaining', maxRequests - timestamps.length);
    res.setHeader('X-RateLimit-Reset',     resetEpochSec);

    next();
  }

  // ── Lifecycle ──────────────────────────────────────────────────────────────

  /**
   * Stops the background cleanup interval.
   * Call this during graceful shutdown so the event loop can drain cleanly.
   */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
```

