 *
 * Implements a TRUE sliding window log algorithm (not a fixed/bucketed window).
 * Every request stores its exact timestamp. On each incoming request we:
 *   1. Drop all timestamps older than (now - windowMs)
 *   2. Count what's left
 *   3. Decide allow/reject based on that live count
 *
 * This gives smooth, accurate rate limiting with no "reset burst" problems
 * that plague naive fixed-window counters.
 */

const DEFAULT_WINDOW_MS = 60_000;     // 1 minute
const DEFAULT_MAX_REQUESTS = 100;
const CLEANUP_INTERVAL_MS = 60_000;   // 60 seconds

/**
 * Factory that creates an Express-compatible rate limiting middleware.
 *
 * @param {Object} [options={}]
 * @param {number} [options.windowMs=60000]   - Duration of the sliding window (ms)
 * @param {number} [options.maxRequests=100]  - Maximum requests allowed inside any window
 * @returns {Function} The middleware. The function also exposes:
 *   - .close()            → stops the internal cleanup timer (call on shutdown)
 *   - ._store (Map)       → internal IP→timestamps map (mainly for testing)
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? DEFAULT_WINDOW_MS;
  const maxRequests = options.maxRequests ?? DEFAULT_MAX_REQUESTS;

  // IP -> number[]  (request timestamps in milliseconds, kept sorted ascending)
  const requests = new Map();

  // --------------------------------------------------
  // Periodic memory cleanup (every 60 seconds)
  // Removes IPs that have zero active timestamps left in the window.
  // Using unref() is critical so the timer does not prevent the Node process
  // from exiting when it would otherwise be idle.
  // --------------------------------------------------
  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    const cutoff = now - windowMs;

    // Snapshot keys to safely mutate the Map during iteration
    const ips = Array.from(requests.keys());
    for (const ip of ips) {
      const timestamps = requests.get(ip);
      if (!timestamps) continue;

      const active = timestamps.filter((ts) => ts > cutoff);

      if (active.length === 0) {
        requests.delete(ip);
      } else {
        // Only write back if we actually removed entries (avoids unnecessary Map churn)
        if (active.length !== timestamps.length) {
          requests.set(ip, active);
        }
      }
    }
  }, CLEANUP_INTERVAL_MS);

  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
