    clearInterval(cleanupInterval);
  };

  // Exposed for introspection / unit tests (not part of public API contract)
  rateLimitMiddleware._store = requests;
  rateLimitMiddleware._cleanupInterval = cleanupInterval;

  return rateLimitMiddleware;
}

